import numpy as npimport pandas as pdimport jsonfrom petitRADTRANS.radtrans import Radtransfrom criresviz.common import OPACITYfrom criresviz.models.feature import find_active_regionsfrom config import (    MOLECULES,    PRESSURE,    WAVELENGTH_MIN,    WAVELENGTH_MAX,    TARGET_P,    TARGET_T,    c)"""Compute the wavelength regions where molecular opacity is significant.For each molecule, the script computes a high-resolution opacity spectrumusing petitRADTRANS, identifies the active wavelength regions, and storesthem as JSON files for use by CRIRESViz."""SHOW = False # to plot the opacity once the baseline is removedBASELINE_WIDTH = 40  def compute_opacity(        species: str,) -> list[tuple[float, float]]:    """    Compute the active opacity regions for one molecule.    The opacity spectrum is evaluated on the closest temperature-pressure    grid point available in petitRADTRANS. A rolling-median continuum is    removed before identifying wavelength regions with significant opacity.    Parameters    ----------    species : str        Molecule name understood by petitRADTRANS.    Returns    -------    list of tuple        Active wavelength intervals in microns.    """    atmosphere = Radtrans(    pressures=PRESSURE,    line_species=[species],    wavelength_boundaries=np.array([WAVELENGTH_MIN, WAVELENGTH_MAX]),    line_opacity_mode="lbl",    )        pt_grid = (        atmosphere.lines_loaded_opacities        ["temperature_pressure_grid"][species]    )        distance = (        (pt_grid[:,0] - TARGET_T)**2        +        (np.log10(pt_grid[:,1]) - np.log10(TARGET_P))**2    )        index = np.argmin(distance)        opacity = (        atmosphere.lines_loaded_opacities        ["opacity_grid"][species][0, :, index]    )        wavelength_um = (c / atmosphere.frequencies) * 1e4    kernel = int(BASELINE_WIDTH / np.median(np.diff(wavelength_um)))    baseline = pd.Series(opacity).rolling(kernel | 1, center=True, min_periods=1).median().to_numpy()    opacity = opacity - baseline        regions = find_active_regions(        wavelength_um,        opacity,        show=SHOW,    )        return regions           def write_opacity_database(    regions: list[tuple[float, float]],    species: str,) -> None:    """    Save the active opacity regions to a JSON file.    """    metadata = {        "version": 1,        "species": species,        "temperature": TARGET_T,        "pressure": TARGET_P,        "pressure_unit": "Pa",        "wavelength_range": [WAVELENGTH_MIN, WAVELENGTH_MAX],        "wavelength_unit": "micron",        "opacity_mode": "lbl",        "threshold": 0.6,        "source": "petitRADTRANS",        "active_regions": regions,            }    with open(OPACITY / f"{species}.json", "w") as f:        json.dump(            metadata,            f,            indent=4,        )    print(f"Saved {species}.json")def main():    for species in MOLECULES:            print(f"Computing {species}")            regions = compute_opacity(species)            write_opacity_database(            regions,            species,        )if __name__ == "__main__":    main()